//! Spec-compliance tests: Document Structure (ISO 29500-1 §17.3, §17.6)
//!
//! These tests verify our implementation against specific OOXML document
//! structure constructs (flow control, section properties, indentation).
//! Tests marked `#[ignore]` document known gaps.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::PageOrientation;

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/structure";

// -- flow control properties ------------------------------------------------

/// ISO 29500-1 §17.3.1.14: w:keepNext keeps paragraph with next paragraph.
#[test]
fn spec_keep_next_is_exposed() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "flow-control-keep-next");

    let paras = common::all_paragraphs(&doc);
    assert!(
        paras.len() >= 2,
        "should have at least 2 paragraphs, got {}",
        paras.len()
    );

    assert_eq!(
        paras[0].keep_next,
        Some(true),
        "first paragraph should have keep_next = Some(true)"
    );
}

